using System;

// Test stackalloc with Span<nint> and Span<nuint>
Span<nint> signed = stackalloc nint[4];
for (int i = 0; i < signed.Length; i++)
    signed[i] = i * 10;

Span<nuint> unsigned = stackalloc nuint[4];
for (int i = 0; i < unsigned.Length; i++)
    unsigned[i] = (nuint)(i * 100);

Console.WriteLine($"nint size:  {sizeof(nint)} bytes");
Console.WriteLine($"nuint size: {sizeof(nuint)} bytes");
Console.WriteLine();

Console.Write("Span<nint>:  ");
foreach (var v in signed) Console.Write($"{v} ");
Console.WriteLine();

Console.Write("Span<nuint>: ");
foreach (var v in unsigned) Console.Write($"{v} ");
Console.WriteLine();

